 1	import React, { FC } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { Divider, SelectGroup, SelectList } from '@patternfly/react-core';
 7	
 8	import { SourceTypes } from '../../utils/types';
 9	
10	import DiskSourceOption from './components/DiskSourceOption/DiskSourceOption';
11	import { attachExistingGroupOptions, blankOption } from './utils/constants';
12	
13	import './DiskSourceSelect.scss';
14	
15	type DiskSourceSelectProps = {
16	  className?: string;
17	  onSelect: (value: SourceTypes) => void;
18	};
19	
20	const DiskSourceSelect: FC<DiskSourceSelectProps> = ({ className, onSelect }) => {
21	  const { t } = useKubevirtTranslation();
22	  return (
23	    <FormPFSelect
24	      className={classNames('disk-source-select', className)}
25	      onSelect={(_, val) => onSelect(val as SourceTypes)}
26	      selectedLabel={t('Add disk')}
27	      toggleProps={{ variant: 'primary' }}
28	    >
29	      <SelectList>
30	        <DiskSourceOption {...blankOption} onSelect={onSelect} />
31	        <Divider />
32	        <SelectGroup
33	          className="disk-source-select__group-title"
34	          label={attachExistingGroupOptions.groupLabel}
35	        >
36	          {attachExistingGroupOptions.items.map((item) => (
37	            <DiskSourceOption key={item.id} {...item} onSelect={onSelect} />
38	          ))}
39	        </SelectGroup>
40	      </SelectList>
41	    </FormPFSelect>
42	  );
43	};
44	
45	export default DiskSourceSelect;

